package com.example.akkahttp

import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.stream.ActorMaterializer

object WebhookProxyService {
  def main(args: Array[String]): Unit = {
    implicit val system = ActorSystem("webhook-proxy")
    implicit val materializer = ActorMaterializer()

    val route = path("webhook" / Segment) { url =>
      post {
        entity(as[String]) { body =>
          val userUrl = new URL(body)
          Http().singleRequest(HttpRequest(uri = userUrl))
            .map(_.entity.toStrict(1024).getData())
            .map(data => Ok(data))
        }
      }
    }

    val bindingFuture = Http().bindAndHandleSync(route, "localhost", 8080)

    println(s"Server online at http://localhost:8080/\nPress RETURN to stop...")
    StdIn.readLine()
    bindingFuture
      .flatMap(_.unbind())
      .onComplete(_ => system.terminate())
  }
}